// 2.8.1 | 2022-12-30| raj  |  DFCT0011560 - Banner Notification  should display the label My Conflicting Schedules (OOO) (shorter name)
//
// Script Continued Below
oooSave();

function oooSave(){
	new Organization_uiAction().uiAction_createOoO(current);  
	// insert was successful
	if(!current.isNewRecord()){
		var user_id = current.u_user;
		var dt_ooo = new Out_of_Office();
		gs.addInfoMessage(gs.getMessage("Tasker - Success! You are scheduled to be out of the office."));
		if(dt_ooo.getUserOOOTaskConflictCount(user_id)){
			var userTaskConflict_link = dt_ooo.getUserOOOTaskConflictURL(user_id);
			gs.addInfoMessage(
				gs.getMessage("Tasker - Some tasks are assigned to you while you are Out of Office.") + 
				" " + userTaskConflict_link);
		}
	}
}
